import Point from '../view/route-point-view.js';
import CreateForm from '../view/form-edit-view.js';
import TripEvents from '../view/trip-events-view.js';

import { render, RenderPosition } from '../render.js';

export default class TripPresentor {
  constructor({ container, pointsModel }) {
    this.container = container;
    this.pointsModel = pointsModel;
    this.pointViews = [];
  }

  init() {
    // Получаем данные из модели
    const points = this.pointsModel.getPoints();
    const destinations = this.pointsModel.getDestinations();
    const offers = this.pointsModel.getOffers();

    // Рендерим форму создания (с пустыми данными)
    render(new CreateForm(), this.container, RenderPosition.BEFOREEND);
    
    // Рендерим контейнер для событий
    render(new TripEvents(), this.container, RenderPosition.BEFOREEND);
    
    // Находим список для точек
    const eventsList = document.querySelector('.trip-events__list');
    if (!eventsList) return;

    // Рендерим каждую точку маршрута
    points.forEach(point => {
      // Находим направление по ID
      const destination = destinations.find(dest => dest.id === point.destination);
      
      // Находим офферы для этого типа и ID
      const offersByType = this.pointsModel.getOffersByType(point.type);
      const pointOffers = offersByType ? offersByType.offers.filter(offer => 
        point.offers?.includes(offer.id)
      ) : [];
      
      // Создаём и рендерим представление точки
      const pointView = new Point(point, destination, pointOffers);
      render(pointView, eventsList, RenderPosition.BEFOREEND);
      this.pointViews.push(pointView);
    });
  }
}